// ─── UTILS ────────────────────────────────────────────────────────────────────
function hexToHsl(hex) {
  let r=0,g=0,b=0;
  if(hex.length===4){r=parseInt(hex[1]+hex[1],16);g=parseInt(hex[2]+hex[2],16);b=parseInt(hex[3]+hex[3],16);}
  else{r=parseInt(hex.slice(1,3),16);g=parseInt(hex.slice(3,5),16);b=parseInt(hex.slice(5,7),16);}
  r/=255;g/=255;b/=255;
  const max=Math.max(r,g,b),min=Math.min(r,g,b);let h,s,l=(max+min)/2;
  if(max===min){h=s=0;}else{const d=max-min;s=l>0.5?d/(2-max-min):d/(max+min);
    switch(max){case r:h=((g-b)/d+(g<b?6:0))/6;break;case g:h=((b-r)/d+2)/6;break;case b:h=((r-g)/d+4)/6;break;}}
  return[Math.round(h*360),Math.round(s*100),Math.round(l*100)];
}
function hDist(h1,h2){const d=Math.abs(h1-h2);return Math.min(d,360-d);}
function similarShades(p,all,n=6){
  const[h1]=hexToHsl(p.hexColor||"#888");
  return all.filter(x=>x.id!==p.id).sort((a,b)=>hDist(h1,hexToHsl(a.hexColor||"#888")[0])-hDist(h1,hexToHsl(b.hexColor||"#888")[0])).slice(0,n);
}

